var raw=$input.first().json;
function pj(x){if(typeof x!=='string')return x;try{return JSON.parse(x)}catch(e){return null}}
function isO(v){return v!==null&&typeof v==='object'&&!Array.isArray(v)}
function g(o,k1,k2){if(!isO(o))return null;var v=o[k1];if(v!=null&&v!=='')return v;if(k2){v=o[k2];if(v!=null&&v!=='')return v}return null}
var payload=isO(raw)?raw:{};
if(isO(raw)&&raw.body!==undefined)payload=typeof raw.body==='string'?pj(raw.body):raw.body;
if(!isO(payload))payload={};
var data=isO(payload.data)?payload.data:payload;
if(!isO(data))data=payload;
var tenantId=g(payload,'tenantId')||g(data,'tenantId')||g(raw,'tenantId');
var articleId=g(data,'articleId','article_id')||g(payload,'articleId','article_id');
var siteId=g(data,'siteId','site_id')||g(payload,'siteId','site_id');
var typeMouvement=g(data,'typeMouvement','type_mouvement')||g(payload,'typeMouvement','type_mouvement');
var quantity=g(data,'quantity')||g(payload,'quantity');
if(!tenantId||!articleId||!siteId||!typeMouvement||quantity==null)return [{json:{_error:true,message:'tenantId, articleId, siteId, typeMouvement et quantity requis'}}];
var body={tenantId,articleId,siteId,typeMouvement,quantity:Number(quantity)};
var ref=g(data,'reference')||g(payload,'reference');if(ref)body.reference=ref;
var notes=g(data,'notes')||g(payload,'notes');if(notes)body.notes=notes;
return [{json:body}];

var p = $('02. Parser').first().json;
var reference = (p.reference || '').replace(/'/g, "''");
var notes = (p.notes || '').replace(/'/g, "''");
var query = `BEGIN TRANSACTION;
INSERT INTO stock_movements (id, tenant_id, article_id, site_id, type_mouvement, quantity, date_operation, reference, notes, created_at, updated_at) VALUES (gen_random_uuid(), '${p.tenantId}', '${p.articleId}', '${p.siteId}', '${p.typeMouvement}', ${p.quantity}, NOW(), '${reference}', '${notes}', NOW(), NOW());
UPDATE stock_levels SET quantity = quantity + ${p.quantity}, updated_at = NOW() WHERE article_id = '${p.articleId}' AND site_id = '${p.siteId}' AND tenant_id = '${p.tenantId}';
COMMIT;`;
return [{json:{query}}];
